<svelte:options customElement="octo-thorpe" />

<script>
  import { onMount } from 'svelte';
  import { createOctoQuery } from '../shared/octo-store.js';
  import { getTitle, getUrl, formatDate } from '../shared/display-helpers.js';

  // API Configuration
  export let server = 'https://octothorp.es';

  // Query parameters - map directly to API
  export let o = '';           // Objects (thorpe terms) - comma-separated
  export let s = '';           // Subjects (domain filters) - comma-separated
  export let noto = '';        // Exclude objects
  export let nots = '';        // Exclude subjects
  export let match = '';       // Match mode: exact, fuzzy, fuzzy-o, fuzzy-s, very-fuzzy
  export let limit = '10';     // Result limit
  export let offset = '0';     // Result offset
  export let when = '';        // Date filter: recent, after-DATE, before-DATE, between-DATE-and-DATE

  // Behavior
  export let autoload = false;  // Auto-load on mount
  export let render = 'compact';   // Render mode: list, cards, compact, count
  export let nopreload = false; // Opt out of injecting the preload link

  // Create the query store (always queries pages/thorped)
  const query = createOctoQuery('pages', 'thorped');

  let hasLoaded = false;
  let rootEl;
  // Term displayed in the summary; resolved in onMount from `o` or light-DOM text.
  let displayTerm = o;

  // Load function
  async function load() {
    hasLoaded = true;
    await query.fetch({
      server,
      s,
      o,
      nots,
      noto,
      match,
      limit,
      offset,
      when
    });
  }

  // Fire the first load when the compact details is opened
  function handleToggle(event) {
    if (event.target.open && !hasLoaded) {
      load();
    }
  }

  // Inject a <link rel="preload" as="fetch"> pointing at the indexing endpoint.
  // Mirrors the legacy static/tag.js behavior: if a preload link with an empty
  // href already exists, fill it; otherwise append a new one to <head>.
  function injectPreloadLink() {
    if (typeof document === 'undefined' || typeof window === 'undefined') return;
    const href = `${server}?uri=${encodeURI(window.location.href)}`;
    const existing = document.querySelector('link[rel="preload"][as="fetch"]');
    if (existing) {
      const current = (existing.getAttribute('href') || '').trim();
      if (!current) existing.setAttribute('href', href);
      return;
    }
    const link = document.createElement('link');
    link.setAttribute('rel', 'preload');
    link.setAttribute('as', 'fetch');
    link.setAttribute('href', href);
    document.head.appendChild(link);
  }

  onMount(() => {
    // Resolve term: explicit `o` attribute wins; otherwise read light-DOM text
    // off the custom element host, matching tag.js's `node.innerText.trim()`.
    if (!o) {
      const host = rootEl?.getRootNode?.().host;
      const text = host?.textContent?.trim();
      if (text) {
        o = text;
        displayTerm = text;
      }
    }

    // Inject preload unless explicitly disabled
    if (!(nopreload === true || nopreload === 'true' || nopreload === '')) {
      injectPreloadLink();
    }

    if (autoload || autoload === '') {
      load();
    }
  });

  // (Common display helpers imported from display-helpers.js)
</script>

{#if render === 'count'}
  <!-- Just show the count -->
  <span bind:this={rootEl} class="count-wrap">
    {#if $query.loading}
      <span class="count-loading">…</span>
    {:else if $query.error}
      <span class="count-error">✗</span>
    {:else}
      <span class="count">{$query.count}</span>
    {/if}
  </span>

{:else if render === 'compact'}
  <details bind:this={rootEl} class="compact" on:toggle={handleToggle}>
    <summary>{displayTerm || 'octothorpes'}</summary>
    {#if $query.loading}
      <p class="compact-status">Loading…</p>
    {:else if $query.error}
      <p class="compact-status compact-error">Error: {$query.error}</p>
    {:else if $query.results.length > 0}
      <ul>
        {#each $query.results as item}
          <li>
            <a href={getUrl(item)} target="_blank" rel="noopener noreferrer">
              {getTitle(item)}
            </a>
          </li>
        {/each}
      </ul>
    {/if}
  </details>

{:else}
  <!-- Full component display -->
  <div bind:this={rootEl} class="octo-thorpe">

    {#if !$query.results.length && !$query.loading && !$query.error}
      <button on:click={load} class="load-button">
        Load pages tagged "{displayTerm || 'octothorpes'}"
      </button>
    {/if}

    {#if $query.loading}
      <div class="loading">
        <div class="spinner"></div>
        <p>Loading...</p>
      </div>
    {/if}

    {#if $query.error}
      <div class="error">
        <p><strong>Error:</strong> {$query.error}</p>
        <button on:click={load} class="retry-button">Retry</button>
      </div>
    {/if}

    {#if $query.results.length > 0 && !$query.loading}

      {#if render === 'list'}
        <ul class="list">
          {#each $query.results as item}
            <li>
              <a href={getUrl(item)} target="_blank" rel="noopener noreferrer">
                {getTitle(item)}
              </a>
              {#if item.description}
                <p class="description">{item.description}</p>
              {/if}
              {#if item.date}
                <time class="date">{formatDate(item.date)}</time>
              {/if}
            </li>
          {/each}
        </ul>

      {:else if render === 'cards'}
        <div class="cards">
          {#each $query.results as item}
            <article class="card">
              {#if item.image}
                <img src={item.image} alt={getTitle(item)} loading="lazy" />
              {/if}
              <h3>
                <a href={getUrl(item)} target="_blank" rel="noopener noreferrer">
                  {getTitle(item)}
                </a>
              </h3>
              {#if item.description}
                <p class="description">{item.description}</p>
              {/if}
              {#if item.date}
                <time class="date">{formatDate(item.date)}</time>
              {/if}
            </article>
          {/each}
        </div>
      {/if}

      <div class="meta">
        <span class="result-count">{$query.count} result{$query.count === 1 ? '' : 's'}</span>
      </div>

    {/if}

  </div>
{/if}

<style>
  /* CSS Custom Properties - all customizable */
  :host {
    --octo-font: system-ui, -apple-system, sans-serif;
    --octo-primary: blue;
    --octo-background: #ffffff;
    --octo-text: #333333;
    --octo-border: #e0e0e0;
    --octo-error: #d32f2f;
    --octo-spacing: 1rem;
    --octo-radius: 4px;

    display: block;
    font-family: var(--octo-font);
    color: var(--octo-text);
  }

  .octo-thorpe {
    background: var(--octo-background);
  }

  /* Count mode (inline) */
  .count,
  .count-loading,
  .count-error {
    font-weight: bold;
  }

  .count-loading {
    opacity: 0.5;
  }

  .count-error {
    color: var(--octo-error);
  }

  /* Buttons */
  .load-button,
  .retry-button {
    background: var(--octo-primary);
    color: white;
    border: none;
    padding: 0.75rem 1.5rem;
    font-size: 1rem;
    font-family: var(--octo-font);
    border-radius: var(--octo-radius);
    cursor: pointer;
    transition: opacity 0.2s;
  }

  .load-button:hover,
  .retry-button:hover {
    opacity: 0.9;
  }

  .retry-button {
    background: var(--octo-error);
  }

  /* Loading state */
  .loading {
    text-align: center;
    padding: calc(var(--octo-spacing) * 2);
  }

  .spinner {
    width: 10px;
    height: 10px;
    margin: 0 auto var(--octo-spacing);
    border: 4px solid var(--octo-border);
    border-top-color: var(--octo-primary);
    border-radius: 50%;
    animation: spin 1s linear infinite;
  }

  @keyframes spin {
    to { transform: rotate(360deg); }
  }

  .loading p {
    margin: 0;
    color: #666;
  }

  /* Error state */
  .error {
    padding: var(--octo-spacing);
    background: #ffebee;
    border: 1px solid var(--octo-error);
    border-radius: var(--octo-radius);
    text-align: center;
  }

  .error p {
    color: var(--octo-error);
    margin: 0 0 var(--octo-spacing) 0;
  }

  /* List render mode */
  .list {
    list-style: none;
    padding: 0;
    margin: 0;
  }

  .list li {
    padding: var(--octo-spacing);
    border-bottom: 1px solid var(--octo-border);
  }

  .list li:last-child {
    border-bottom: none;
  }

  /* Cards render mode */
  .cards {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(250px, 1fr));
    gap: var(--octo-spacing);
  }

  .card {
    padding: var(--octo-spacing);
    border: 1px solid var(--octo-border);
    border-radius: var(--octo-radius);
    background: var(--octo-background);
  }

  .card img {
    width: 100%;
    height: auto;
    border-radius: var(--octo-radius);
    margin-bottom: 0.5rem;
  }

  .card h3 {
    margin: 0 0 0.5rem 0;
    font-size: 1.125rem;
  }

  /* Compact render mode — details/summary, modeled on static/tag.js */
  .compact {
    display: inline;
  }

  .compact[open] {
    display: block;
  }

  .compact summary {
    list-style: none;
    cursor: zoom-in;
  }

  .compact summary::-webkit-details-marker {
    display: none;
  }

  .compact summary::before {
    padding-inline-end: 0.1em;
    content: "#";
    font-weight: bold;
    display: inline-block;
    transform: rotate(30deg);
  }

  .compact[open] summary::before {
    transform: rotate(0);
  }

  .compact ul {
    padding: 0 0 1em 1em;
    margin: 0;
  }

  .compact a {
    color: inherit;
  }

  .compact-status {
    padding: 0 0 1em 1em;
    margin: 0;
    font-style: italic;
    opacity: 0.7;
  }

  .compact-error {
    color: var(--octo-error);
    font-style: normal;
    opacity: 1;
  }

  /* Common elements */
  a {
    color: var(--octo-primary);
    text-decoration: none;
  }

  a:hover {
    text-decoration: underline;
  }

  .description {
    margin: 0.5rem 0 0 0;
    color: #666;
    font-size: 0.875rem;
    line-height: 1.4;
  }

  .date {
    display: block;
    margin-top: 0.25rem;
    font-size: 0.75rem;
    color: #999;
  }

  /* Meta info */
  .meta {
    margin-top: var(--octo-spacing);
    padding-top: var(--octo-spacing);
    border-top: 1px solid var(--octo-border);
    text-align: right;
  }

  .result-count {
    font-size: 0.875rem;
    color: #666;
  }
</style>
